function data = mdp_PalDist(data, varargin)%MDP_PALDIST  - MVIEW dataproc that computes distance of tongue pellets from palate%% by default applies to all trajectories beginning with 'T'% to use specific names specify cellstr varargin{1} as e.g. {'TT','TD'}%% appends T*_DIST signals to DATA%% usage examples: %% use default "T*"% mview(...,'DPROC','mdp_PalDist',...)%% use trajectories names "T1", "T4"% mview(...,'DPROC',{{'mdp_PalDist',{'T1','T4'}}}, ...)% mkt 11/01pal = varargin{end}{1};if isempty(pal),	warning('need palate data'); 	return; end;pdims = size(pal,2);traj = varargin{1};% find indices of tongue sensors within data (all those beginning with 'T')tn = char({data.NAME}');if isempty(traj),	tidx = find(tn(:,1) == 'T')';else,	tidx = [];	if ~iscellstr(traj), traj = {traj}; end;	for ti = 1 : length(traj),		k = strmatch(upper(traj{ti}),tn,'exact');		if isempty(k), continue; end;		tidx = [tidx;k];	end;end;if isempty(tidx),	error('no tongue trajectories found in data');end;% resample palate to 200 equally spaced intervalsk = [0 ; cumsum(sqrt(sum(diff(pal).^2,2)))];pal = interp1(k,pal,linspace(0,k(end),200));px = pal(:,1)';py = pal(:,2)';if pdims > 2, pz = pal(:,3)'; end;nps = length(px);[b,a] = butter(3,.2);		% 20 Hz lowpass Fc% loop over tongue trajectoriesfor ti = tidx,	[ns,nComps] = size(data(ti).SIGNAL);% find minimum distance from palate for each sample	dx = repmat(px,ns,1) - repmat(data(ti).SIGNAL(:,1),1,nps);	dy = repmat(py,ns,1) - repmat(data(ti).SIGNAL(:,2),1,nps);	if pdims > 2, dz = repmat(pz,ns,1) - repmat(data(ti).SIGNAL(:,3),1,nps); else, dz = 0; end;	n = length(data) + 1;		% append to end of dataset	data(n).NAME = [data(ti).NAME '_DIST'];	data(n).SRATE = data(ti).SRATE;	data(n).NCOMPS = 1;	[s,si] = min(sqrt(dx.^2 + dy.^2 + dz.^2),[],2);% negate (want increasing values to correspond with movement towards palate)	s = -(s);	s = FixNaN(double(s));		% invert sign of points that have 'passed through' palate% ASSUMPTION:  X is posterior->anterior, Y is lateral, Z is inferior->superior	qi = sub2ind([ns nps], [1:ns]', si);	dx = dx(qi); 		if pdims < 3, dz = dy; end;	dz = dz(qi); 	th = atan2(dz,dx);	si = find(th < 0);	s(si) = -s(si);	s = filtfilt(b,a,s);	% low pass		data(n).SIGNAL = s;	minS = min(s);	maxS = max(s);	spread = maxS - minS;	data(n).SPREAD = [minS-spread*.1 maxS+spread*.1];	% pad	end;